import React from 'react';
import { Card, CardContent, Box, Typography, Stack, Chip } from '@mui/material';
import response from './response.json';

interface Meeting {
  title: string;
  time: string;
  location: string;
}

interface AgendaData {
  nextMeetings: Meeting[];
}

export default function Widget() {
  const agendaData = response.data as AgendaData;
  const { nextMeetings } = agendaData;

  return (
    <Card sx={{ width: 'fit-content', minWidth: 320, maxWidth: 450, bgcolor: '#FFFFFF' }} elevation={2}>
      <CardContent sx={{ p: 2 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="h6" fontWeight={600} sx={{ color: '#1976D2' }}>
              Upcoming Meetings
            </Typography>
          </Box>
          <Stack spacing={1}>
            {nextMeetings.map((meeting, index) => (
              <Box key={index} sx={{ borderBottom: index < nextMeetings.length - 1 ? '1px solid #E0E0E0' : 'none', pb: 1, mb: 1 }}>
                <Typography variant="body1" fontWeight={500} sx={{ color: '#333' }}>
                  {meeting.title}
                </Typography>
                <Stack direction="row" spacing={1} alignItems="center">
                  <Chip label={meeting.time} sx={{ fontSize: '11px', bgcolor: '#F1F1F1', color: '#555' }} />
                  <Chip label={meeting.location} sx={{ fontSize: '11px', bgcolor: '#F1F1F1', color: '#555' }} />
                </Stack>
              </Box>
            ))}
          </Stack>
        </Stack>
      </CardContent>
    </Card>
  );
}
